from fastapi import Depends, FastAPI
from auth0_fastapi_api import Auth0FastAPI

app = FastAPI()
auth0 = Auth0FastAPI(
    domain="your-tenant.us.auth0.com",
    audience="https://api.example.com"
)

@app.get("/profile")
async def get_profile(claims: dict = Depends(auth0.require_auth())):
    return {"user_id": claims["sub"]}

@app.get("/items")
async def list_items(claims: dict = Depends(auth0.require_auth(scopes=["read:items"]))):
    return {"items": []}

@app.post("/items")
async def create_item(claims: dict = Depends(auth0.require_auth(scopes=["write:items"]))):
    return {"created": True}

cache-adapter.description:
Abstract base class for cache implementations.

Allows custom cache backends (Redis, Memcached, etc.) to be plugged into
the ApiClient for caching OIDC discovery metadata and JWKS.

Example:
    class RedisCache(CacheAdapter):
        def __init__(self, redis_client):
            self.redis = redis_client

        def get(self, key: str) -> Optional[Any]:
            value = self.redis.get(key)
            return json.loads(value) if value else None

        def set(self, key: str, value: Any, ttl_seconds: Optional[int] = None) -> None:
            self.redis.set(key, json.dumps(value), ex=ttl_seconds)

        def delete(self, key: str) -> None:
            self.redis.delete(key)

        def clear(self) -> None:
            self.redis.flushdb()

