from auth0_fastapi_api import Auth0FastAPI, DomainsResolverContext

def resolve_domains(ctx: DomainsResolverContext) -> list[str]:
    if ctx.unverified_iss.endswith('.us.auth0.com'):
        return ['tenant-a.us.auth0.com']
    return ['tenant-b.eu.auth0.com']

auth0 = Auth0FastAPI(
    domains=resolve_domains,
    audience='https://api.example.com'
)
